<span class="line"><span style="color:#CDD6F4;">            cached_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">current_tokens</span><span style="color:#CBA6F7;"> as</span><span style="color:#CBA6F7;"> f32</span><span style="color:#94E2D5;"> *</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">.</span><span style="color:#FAB387;">8</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> as</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;"> // Assume 80% cache hit</span></span>
